('business:3-1-role-of-human-resources:match:49fd75cb', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Human resources”?", "options": ["A plan detailing the workers a business needs — how many, full- or part-time, the skills they should have, and when they will work", "The people who do the work for a business — including owners, employees, and contractors", "The activity of thinking about the purposes of human resources and deciding how many and what types of workers will be needed", "A contract given to an employee which does not guarantee any work — the business calls workers in as and when they are needed"]}'::jsonb, '{"answer": 1, "explain": "“Human resources” means: The people who do the work for a business — including owners, employees, and contractors"}'::jsonb),
('business:3-1-role-of-human-resources:match:80e55475', 'business', 'business:3-1-role-of-human-resources', '3.1 Role of Human Resources', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Human resource plan”?", "options": ["The activity of thinking about the purposes of human resources and deciding how many and what types of workers will be needed", "A plan detailing the workers a business needs — how many, full- or part-time, the skills they should have, and when they will work", "A contract given to an employee which does not guarantee any work — the business calls workers in as and when they are needed", "Different types of work that need to be done in a business — including production, finance, marketing, and HR"]}'::jsonb, '{"answer": 1, "explain": "“Human resource plan” means: A plan detailing the workers a business needs — how many, full- or part-time, the skills they should have, and when they will work"}'::jsonb),
